import{_ as i,c as e,o as t,a4 as a}from"./chunks/framework.BxjRYGQi.js";const k=JSON.parse('{"title":"Synchronize Robot Pose to RViz Display","description":"","frontmatter":{},"headers":[],"relativePath":"en/02-quick-start/05-Synchronize_robot_pose.md","filePath":"en/02-quick-start/05-Synchronize_robot_pose.md"}'),o={name:"en/02-quick-start/05-Synchronize_robot_pose.md"};function n(r,s,h,l,p,d){return t(),e("div",{"data-pagefind-body":!0},s[0]||(s[0]=[a(`<h1 id="synchronize-robot-pose-to-rviz-display" tabindex="-1">Synchronize Robot Pose to RViz Display <a class="header-anchor" href="#synchronize-robot-pose-to-rviz-display" aria-label="Permalink to “Synchronize Robot Pose to RViz Display”">​</a></h1><p>When programming or controlling robots from Shanghai Agilebot Robotics Co., Ltd., you may need to synchronize the robot&#39;s pose (position and orientation) to <strong>RViz</strong> for visualization. Below are the steps to achieve this:</p><hr><h2 id="step-1-configure-robot-ip-address" tabindex="-1">Step 1: Configure Robot IP Address <a class="header-anchor" href="#step-1-configure-robot-ip-address" aria-label="Permalink to “Step 1: Configure Robot IP Address”">​</a></h2><p>Edit the <code>gbt_driver/config/robot_config.yaml</code> file and set the <code>robot_ip_address</code> field to the actual IP address of your robot.</p><p>Then, start the feedback service:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install/setup.bash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_feedback.launch.py</span></span></code></pre></div><hr><h2 id="step-2-synchronize-arm-state-to-urdf" tabindex="-1">Step 2: Synchronize Arm State to URDF <a class="header-anchor" href="#step-2-synchronize-arm-state-to-urdf" aria-label="Permalink to “Step 2: Synchronize Arm State to URDF”">​</a></h2><p>Launch <code>rviz2</code> and synchronize the robotic arm&#39;s state to the URDF model:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install/setup.bash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_bridge.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:={robot_model}</span></span></code></pre></div><p><strong>Example for C5A model:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install/setup.bash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_bridge.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:=C5A</span></span></code></pre></div><p>You can now view the robotic arm&#39;s real-time state in <strong>RViz</strong>.</p><hr><blockquote><p><strong>Note:</strong></p><ul><li>Replace <code>{robot_model}</code> with the actual robot model name (e.g., <code>C5A</code> , <code>C7A</code> , <code>C12A</code> , <code>C16A</code> ).</li><li>Ensure the robot&#39;s network configuration is correct before launching.</li><li>For additional configuration details, refer to the <a href="https://github.com/sh-agilebot/Agilebot_Robot_Ros2" target="_blank" rel="noreferrer">Agilebot ROS2 github</a>.</li></ul></blockquote>`,16)]))}const g=i(o,[["render",n]]);export{k as __pageData,g as default};
